class Trie:
    def __init__(self):
        self.children = {}
        self.end = False

    def insert(self, word):
        node = self
        for ch in word:
            node = node.children.setdefault(ch, Trie())
        node.end = True

    def search(self, word):
        node = self
        for ch in word:
            if ch not in node.children:
                return False
            node = node.children[ch]
        return node.end

    def startsWith(self, prefix):
        node = self
        for ch in prefix:
            if ch not in node.children:
                return False
            node = node.children[ch]
        return True

class Solution:
    def trieOps(self, operations, values):
        trie = None
        out = []
        for op, args in zip(operations, values):
            if op == 'Trie':
                trie = Trie()
            elif op == 'insert':
                trie.insert(args[0])
            elif op == 'search':
                out.append(trie.search(args[0]))
            elif op == 'startsWith':
                out.append(trie.startsWith(args[0]))
        return out
